# correct path (en-dash issues) - use the real one
$path = "D:\이력서\AVEVA - Marine Principal Technical Support & Consultant – PLM SME, Busan\Proposal\Future_Industrial_PLM_Meeting_Deck_EN_Rebuilt_v2.pptx"
$ppt = New-Object -ComObject PowerPoint.Application
try {
    $pres = $ppt.Presentations.Open($path, $true, $false, $false)  # ReadOnly, Untitled=false, WithWindow=false
    Write-Output "SLIDE COUNT: $($pres.Slides.Count)"
    Write-Output "SLIDE SIZE: $($pres.PageSetup.SlideWidth) x $($pres.PageSetup.SlideHeight)"
    $pres.Close()
} finally {
    $ppt.Quit()
    [System.Runtime.Interopservices.Marshal]::ReleaseComObject($ppt) | Out-Null
}

$tmp = "C:\Users\namma\.claude\plm_slide_work\extract_v2"
$ns = @{
  a = "http://schemas.openxmlformats.org/drawingml/2006/main"
  p = "http://schemas.openxmlformats.org/presentationml/2006/main"
}
$slides = Get-ChildItem "$tmp\ppt\slides\*.xml" | Sort-Object { [int]($_.BaseName -replace '\D','') }
foreach ($s in $slides) {
  $num = [int]($s.BaseName -replace '\D','')
  Write-Output "==================== SLIDE $num ===================="
  [xml]$xml = Get-Content $s.FullName -Raw -Encoding UTF8
  # iterate shapes (sp)
  $shapes = $xml.GetElementsByTagName("p:sp")
  foreach ($sp in $shapes) {
    # shape name
    $nm = $null
    try { $nm = $sp.nvSpPr.cNvPr.name } catch {}
    $txt = ""
    $paras = $sp.GetElementsByTagName("a:p")
    foreach ($p in $paras) {
      $runs = $p.GetElementsByTagName("a:t")
      $line = ""
      foreach ($r in $runs) { $line += $r.InnerText }
      if ($line.Trim().Length -gt 0) { $txt += $line + "`n" }
    }
    if ($txt.Trim().Length -gt 0) {
      Write-Output "  [SHAPE: $nm]"
      foreach ($l in ($txt -split "`n")) { if ($l.Trim()) { Write-Output "    $l" } }
    }
  }
}
